    float x1_2 = box2[0], y1_2 = box2[1], x2_2 = box2[2], y2_2 = box2[3];

    // Intersection area
    float inter_x1 = fmaxf(x1_1, x1_2);
    float inter_y1 = fmaxf(y1_1, y1_2);
    float inter_x2 = fminf(x2_1, x2_2);
    float inter_y2 = fminf(y2_1, y2_2);

    float inter_w = fmaxf(0.0f, inter_x2 - inter_x1);
    float inter_h = fmaxf(0.0f, inter_y2 - inter_y1);
    float inter_area = inter_w * inter_h;

    // Union area
    float area1 = (x2_1 - x1_1) * (y2_1 - y1_1);
    float area2 = (x2_2 - x1_2) * (y2_2 - y1_2);
    float union_area = area1 + area2 - inter_area;

    return (union_area > 0.0f) ? (inter_area / union_area) : 0.0f;
}

