// Each thread checks a pair of boxes
__global__ void nms_kernel(const float* boxes, int* keep, int num_boxes, float iou_threshold) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;

    // Each thread processes one box
    if (idx >= num_boxes) return;

    // Assume all boxes are kept initially (set by host)
    // We only need to mark boxes to suppress

    const float* current_box = boxes + idx * 4;

    // Check against all previous boxes (higher score boxes)
    for (int prev_idx = 0; prev_idx < idx; prev_idx++) {
        // If the current box is already suppressed, no need to continue
        if (keep[idx] == 0) break;

        // If the previous box was suppressed, skip it
        if (keep[prev_idx] == 0) continue;

        const float* prev_box = boxes + prev_idx * 4;
