// Sequential NMS implementation for correctness
// Process boxes in order to avoid race conditions
__global__ void nms_kernel_sequential(const float* boxes, int* keep, int num_boxes, float iou_threshold) {
    // Only use thread 0 to ensure sequential processing
    if (threadIdx.x != 0 || blockIdx.x != 0) return;

    // Process each box sequentially
    for (int idx = 0; idx < num_boxes; idx++) {
        // If already suppressed, skip
        if (keep[idx] == 0) continue;

        const float* current_box = boxes + idx * 4;

        // Suppress all subsequent boxes with high IoU
        for (int next_idx = idx + 1; next_idx < num_boxes; next_idx++) {
            if (keep[next_idx] == 0) continue;

            const float* next_box = boxes + next_idx * 4;
            float iou = compute_iou(current_box, next_box);

            if (iou > iou_threshold) {
                keep[next_idx] = 0;
            }
        }
    }
}

// Optimized parallel NMS using batch processing
// Processes boxes in waves to ensure correctness
__global__ void nms_kernel_batched(const float* boxes, int* keep, int num_boxes, 
                                    float iou_threshold, int start_idx) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x + start_idx;

    if (idx >= num_boxes) return;

    // If already suppressed, skip
    if (keep[idx] == 0) return;

    const float* current_box = boxes + idx * 4;

    // Check against all previous kept boxes
    for (int prev_idx = 0; prev_idx < start_idx; prev_idx++) {
        // Only check against kept boxes
        if (keep[prev_idx] == 0) continue;

        const float* prev_box = boxes + prev_idx * 4;
        float iou = compute_iou(current_box, prev_box);

        if (iou > iou_threshold) {
            keep[idx] = 0;
            return;
        }
