    // For small problem sizes, use sequential kernel
    if (num_boxes <= 1024) {
        nms_kernel_sequential<<<1, 1>>>(boxes, keep, num_boxes, iou_threshold);
        cudaDeviceSynchronize();
        return;
    }

    // For larger sizes, use batched approach
    const int batch_size = 256;
    const int threads_per_block = 256;

    for (int start = 0; start < num_boxes; start += batch_size) {
        int remaining = num_boxes - start;
        int current_batch = (remaining < batch_size) ? remaining : batch_size;
        int num_blocks = (current_batch + threads_per_block - 1) / threads_per_block;

        nms_kernel_batched<<<num_blocks, threads_per_block>>>(
