// NMS kernel that processes multiple reference boxes in parallel
// Uses a block-based approach where each block handles comparisons for one reference box
__global__ void nms_kernel_blockwise(const float* boxes, int* keep, int num_boxes, 
                                       float iou_threshold, int ref_start, int ref_end) {
    // Each block processes one reference box
    int ref_idx = blockIdx.x + ref_start;
    if (ref_idx >= ref_end || ref_idx >= num_boxes) return;

    // Skip if reference box is already suppressed
    if (keep[ref_idx] == 0) return;

    const float* ref_box = boxes + ref_idx * 4;

    // Each thread in the block checks a different target box
    for (int idx = ref_idx + 1 + threadIdx.x; idx < num_boxes; idx += blockDim.x) {
        // Skip if already suppressed
        if (keep[idx] == 0) continue;

        const float* current_box = boxes + idx * 4;
        float iou = compute_iou(ref_box, current_box);

        // Suppress if IoU exceeds threshold
        if (iou > iou_threshold) {
            keep[idx] = 0;
        }
    }
}

// Optimized NMS using bit-masking for small batch sizes
__global__ void nms_kernel_bitmask(const float* boxes, unsigned long long* mask, 
                                    int num_boxes, float iou_threshold) {
    // Each block handles 64 boxes using a bitmask
    const int block_boxes = 64;
    int block_start = blockIdx.x * block_boxes;
    int block_end = min(block_start + block_boxes, num_boxes);

    // Each thread processes one box in the block
    int idx = block_start + threadIdx.x;

    __shared__ float shared_boxes[64 * 4];  // Store 64 boxes in shared memory

    // Load boxes into shared memory
    if (idx < block_end && threadIdx.x < block_boxes) {
        int offset = threadIdx.x * 4;
        shared_boxes[offset + 0] = boxes[idx * 4 + 0];
        shared_boxes[offset + 1] = boxes[idx * 4 + 1];
        shared_boxes[offset + 2] = boxes[idx * 4 + 2];
        shared_boxes[offset + 3] = boxes[idx * 4 + 3];
    }
    __syncthreads();

    if (idx >= num_boxes) return;

    unsigned long long local_mask = 0;
    const float* current_box = boxes + idx * 4;

    // Check against all previous boxes
    for (int prev_idx = 0; prev_idx < idx; prev_idx++) {
        const float* prev_box = boxes + prev_idx * 4;
        float iou = compute_iou(current_box, prev_box);

        if (iou > iou_threshold) {
            local_mask |= (1ULL << (prev_idx % 64));
        }
    }

    mask[idx] = local_mask;
}

// Optimized kernel that minimizes global memory traffic
__global__ void nms_kernel_optimized(const float* boxes, int* keep, int num_boxes, 
                                      float iou_threshold) {
    // Use a grid-stride loop to process boxes
    for (int idx = blockIdx.x * blockDim.x + threadIdx.x; 
         idx < num_boxes; 
         idx += blockDim.x * gridDim.x) {

        // Skip if already suppressed
        if (keep[idx] == 0) continue;

        const float* current_box = boxes + idx * 4;
        bool should_suppress = false;

        // Check against all previous boxes
        for (int prev_idx = 0; prev_idx < idx; prev_idx++) {
            // Skip suppressed boxes
            if (keep[prev_idx] == 0) continue;

            const float* prev_box = boxes + prev_idx * 4;
            float iou = compute_iou(current_box, prev_box);

            if (iou > iou_threshold) {
                should_suppress = true;
                break;
            }
        }

        if (should_suppress) {
            keep[idx] = 0;
        }
    }
}

extern "C" void cuda_kernel(float* boxes, int* keep, int num_boxes, float iou_threshold) {
    const int threads_per_block = 256;
    const int blocks_per_batch = 32;

    // Process in batches to balance parallelism and correctness
    const int batch_size = 32;

    for (int batch_start = 0; batch_start < num_boxes; batch_start += batch_size) {
        int batch_end = min(batch_start + batch_size, num_boxes);
        int batch_count = batch_end - batch_start;
        int num_blocks = min(batch_count, blocks_per_batch);

        nms_kernel_blockwise<<<num_blocks, threads_per_block>>>(
            boxes, keep, num_boxes, iou_threshold, batch_start, batch_end
        );
        cudaDeviceSynchronize();
    }
