// Launcher that processes NMS sequentially for reference boxes but parallelizes comparison
__global__ void nms_kernel_launcher(const float* boxes, int* keep, int num_boxes, 
                                     float iou_threshold) {
    const int threads_per_block = 256;

    // Process each box sequentially as a reference
    for (int ref_idx = 0; ref_idx < num_boxes; ref_idx++) {
        // Load keep status once
        int ref_is_kept = keep[ref_idx];

        // Skip if this box was already suppressed
        if (ref_is_kept == 0) continue;

        int remaining = num_boxes - ref_idx - 1;
        if (remaining <= 0) break;

        int num_blocks = (remaining + threads_per_block - 1) / threads_per_block;

        // Launch nested kernel to parallelize the comparisons
        nms_kernel_parallel<<<num_blocks, threads_per_block>>>(
            boxes, keep, num_boxes, iou_threshold, ref_idx, ref_is_kept
