        // Check if reference is kept (on device, minimize transfers by checking less frequently)
        if (ref_idx % 16 == 0) {
            // Batch check every 16 boxes to reduce overhead
            int keep_val;
            cudaMemcpy(&keep_val, keep + ref_idx, sizeof(int), cudaMemcpyDeviceToHost);
            if (keep_val == 0) {
                // Skip ahead to find next kept box
                continue;
            }
